module top_module(
    input [3:0] A,
    input [3:0] B,
    input [1:0] OP,
    output [3:0] RESULT
);parameter NUM_OPERATIONS = 4;

reg [3:0] ERR_RESULT;

always @(*) begin
    case (OP)
        2'b00: ERR_RESULT = A + B;
        2'b01: ERR_RESULT = A - B;
        2'b10: ERR_RESULT = A * B;
        2'b11: ERR_RESULT = A / B;
    endcase
end

assign RESULT = ERR_RESULT;

endmodule
